export default async function fetchUrl({ data = {}, content }) {
  const {
    url,
    maxSize = 32 * 1024, // 32KB
    cleanHTML = true, // 如果遇到是html内容，是否清理多余标签，只返回包含文本的内容
  } = data;

  const response = await fetch(url);

  if (!response.ok) {
    throw new Error(`HTTP error! status: ${response.status}`);
  }

  data = await response.text();

  // 确定是html内容，才清理多余标签
  if (cleanHTML && data.toLocaleLowerCase().includes("<!doctype html")) {
    data = clearHTML(data);
  }

  if (maxSize && data.length > maxSize) {
    data = data.slice(0, maxSize);
  }

  return data;
}

const clearHTML = (html) => {
  const bodyMatch = html.match(/<body[^>]*>([\s\S]*?)<\/body>/i);
  let bodyContent = bodyMatch ? bodyMatch[1] : html;
  bodyContent = bodyContent.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, "");
  bodyContent = bodyContent.replace(/<svg[^>]*>[\s\S]*?<\/svg>/gi, "");
  bodyContent = bodyContent.replace(/<style[^>]*>[\s\S]*?<\/style>/gi, "");
  bodyContent = bodyContent.replace(
    /<noscript[^>]*>[\s\S]*?<\/noscript>/gi,
    "",
  );
  bodyContent = bodyContent.replace(/<!--[\s\S]*?-->/g, "");
  bodyContent = bodyContent.replace(/<iframe[^>]*>[\s\S]*?<\/iframe>/gi, "");

  const template = document.createElement("template");
  template.innerHTML = bodyContent;
  const allowedAttrs = [
    "href",
    "src",
    "alt",
    "title",
    "role",
    "aria-label",
    "aria-labelledby",
    "aria-describedby",
    "aria-hidden",
    "aria-expanded",
    "aria-disabled",
    "aria-pressed",
    "aria-checked",
    "aria-selected",
    "for",
    "type",
    "name",
    "value",
    "placeholder",
    "disabled",
    "checked",
    "selected",
    "multiple",
    "maxlength",
    "minlength",
    "pattern",
    "required",
    "readonly",
  ];
  template.content.querySelectorAll("*").forEach((el) => {
    const attrs = [...el.attributes];
    attrs.forEach((attr) => {
      if (!allowedAttrs.includes(attr.name) && !attr.name.startsWith("aria-")) {
        el.removeAttribute(attr.name);
      }
    });
  });
  const removeEmpty = (el) => {
    const children = [...el.childNodes];
    children.forEach((child) => {
      if (child.nodeType === 1) {
        removeEmpty(child);
      }
    });
    if (
      el.textContent.trim() === "" &&
      !el.hasAttribute("src") &&
      !el.hasAttribute("href")
    ) {
      el.remove();
    }
  };
  removeEmpty(template.content);
  const simplifyWrappers = (el) => {
    const children = [...el.childNodes];
    children.forEach((child) => {
      if (child.nodeType === 1) {
        simplifyWrappers(child);
        const tagName = child.tagName.toLowerCase();
        if (
          [
            "span",
            "b",
            "i",
            "u",
            "strong",
            "em",
            "small",
            "mark",
            "sub",
            "sup",
          ].includes(tagName)
        ) {
          const textContent = child.textContent;
          const importantAttrs = ["href", "src", "alt", "title", "role"];
          const hasImportantAttr = [...child.attributes].some(
            (attr) =>
              importantAttrs.includes(attr.name) ||
              attr.name.startsWith("aria-"),
          );
          if (
            child.childNodes.length === 1 &&
            child.childNodes[0].nodeType === 3 &&
            !hasImportantAttr
          ) {
            el.replaceChild(document.createTextNode(textContent), child);
          }
        }
      }
    });
  };
  simplifyWrappers(template.content);
  const unwrapNesting = (el) => {
    const children = [...el.childNodes];
    children.forEach((child) => {
      if (child.nodeType === 1) {
        unwrapNesting(child);
        const importantAttrs = [
          "href",
          "src",
          "alt",
          "title",
          "role",
          "for",
          "type",
          "name",
          "value",
          "placeholder",
          "disabled",
          "checked",
          "selected",
        ];
        const hasImportantAttr = [...child.attributes].some(
          (attr) =>
            importantAttrs.includes(attr.name) || attr.name.startsWith("aria-"),
        );
        if (
          child.childNodes.length === 1 &&
          child.childNodes[0].nodeType === 1 &&
          !hasImportantAttr
        ) {
          const inner = child.childNodes[0];
          el.replaceChild(inner.cloneNode(true), child);
        }
      }
    });
  };
  unwrapNesting(template.content);
  return template.innerHTML;
};

import { get } from "/nos/fs/main.js";

export default async function fs({ data = {}, content }) {
  const { mode, path, targetPath, targetName } = data;

  if (!mode) {
    throw new Error("mode is required");
  }
  if (!path) {
    throw new Error("path is required");
  }

  if (mode === "exists") {
    try {
      const testHandle = await get(path);
      return testHandle ? true : false;
    } catch (e) {
      return false;
    }
  }

  const handle = await get(path, {
    create:
      mode === "write" || mode === "mkdir"
        ? mode === "mkdir"
          ? "dir"
          : "file"
        : undefined,
  });

  if (mode === "write") {
    if (!content) {
      throw new Error("没有内容，无法写入");
    }

    const temp = $(`<template>${content}</template>`);
    let textToWrite = temp.ele.content.textContent.trim();

    if (!textToWrite) {
      throw new Error("没有文本内容，无法写入");
    }

    await handle.write(textToWrite);

    return true;
  }

  if (mode === "read") {
    const content = await handle.text();
    return content;
  }

  if (mode === "delete") {
    await handle.remove();
    return true;
  }

  if (mode === "info") {
    const file = await handle.file();
    const lastModified = await handle.lastModified();
    return {
      kind: handle.kind,
      name: handle.name,
      path: handle.path,
      size: file.size,
      lastModified,
    };
  }

  if (mode === "list") {
    if (handle.kind !== "dir") {
      throw new Error("Path is not a directory");
    }

    const items = [];
    await handle.forEach((handle) => {
      items.push({
        name: handle.name,
        kind: handle.kind,
        path: handle.path,
      });
    });
    return items;
  }

  if (mode === "mkdir") {
    return true;
  }

  if (mode === "move") {
    if (!targetPath) {
      throw new Error("targetPath is required for move operation");
    }
    const targetDir = await get(targetPath, { create: "dir" });
    const movedHandle = await handle.moveTo(targetDir, targetName);
    return {
      kind: movedHandle.kind,
      name: movedHandle.name,
      path: movedHandle.path,
    };
  }

  if (mode === "copy") {
    if (!targetPath) {
      throw new Error("targetPath is required for copy operation");
    }
    const targetDir = await get(targetPath, { create: "dir" });
    const copiedHandle = await handle.copyTo(targetDir, targetName);
    return {
      kind: copiedHandle.kind,
      name: copiedHandle.name,
      path: copiedHandle.path,
    };
  }

  throw new Error(`Unknown mode: ${mode}`);
}

import { get } from "/nos/fs/main.js";

export default async ({ data = {}, content }) => {
  const { projectPath } = data;

  if (!projectPath) {
    throw new Error("projectPath is required");
  }

  const aimapList = [];

  const projectDir = await get(projectPath);

  await collectAimapFiles(projectDir, projectPath, aimapList);

  debugger;

  return {
    data: {
      aimaps: aimapList,
    },
  };
};

async function collectAimapFiles(dir, basePath, aimapList, currentPath = "") {
  try {
    const aimapDirPath = currentPath ? `${currentPath}/.aimap` : ".aimap";

    try {
      const aimapDir = await dir.get(aimapDirPath);

      if (aimapDir && aimapDir.kind === "dir") {
        await collectAimapFromDir(aimapDir, basePath, currentPath, aimapList);
      }
    } catch (e) {
      // .aimap 目录不存在，继续处理子目录
    }

    for await (const [name, handle] of dir.entries()) {
      if (handle.kind === "dir" && name !== ".aimap" && !name.startsWith(".")) {
        const subPath = currentPath ? `${currentPath}/${name}` : name;
        await collectAimapFiles(handle, basePath, aimapList, subPath);
      }
    }
  } catch (error) {
    console.error(`Error collecting aimap files from ${currentPath}:`, error);
  }
}

async function collectAimapFromDir(aimapDir, basePath, currentPath, aimapList) {
  for await (const [name, handle] of aimapDir.entries()) {
    if (handle.kind === "file" && name.endsWith(".md")) {
      try {
        const content = await handle.text();

        const originalFileName = name.slice(0, -3);
        const originalFilePath = currentPath
          ? `${currentPath}/${originalFileName}`
          : originalFileName;

        const aimapPath = currentPath
          ? `${currentPath}/.aimap/${name}`
          : `.aimap/${name}`;

        aimapList.push({
          path: originalFilePath,
          aimapPath: aimapPath,
          content: content.trim(),
        });
      } catch (error) {
        console.error(`Error reading aimap file ${name}:`, error);
      }
    }
  }
}

import yaml from "/npm/js-yaml@4.1.1/dist/js-yaml.min.mjs";
import { get } from "/nos/fs/main.js";

export default async function getCapability({ data = {}, content }) {
  const { all, name } = data;

  await new Promise((resolve) => setTimeout(resolve, 500));

  if (all) {
    const capabilityDesc = [];

    try {
      const capDir = await get("mazmot/capabilities");

      if (capDir) {
        for await (const [capabilityName, handle] of capDir.entries()) {
          if (handle.kind === "dir") {
            const skillFile = await get(
              `mazmot/capabilities/${capabilityName}/SKILL.md`,
              { create: false },
            );

            if (skillFile) {
              const capabilityMd = await skillFile.text();

              if (!capabilityMd.trim()) {
                continue;
              }

              const frontMatterMatch = capabilityMd.match(
                /^---\n([\s\S]*?)\n---/,
              );
              const yamlConfig = yaml.load(frontMatterMatch[1]);

              const desc = yamlConfig.description;
              delete yamlConfig.description;

              capabilityDesc.push({
                ...yamlConfig,
                name: capabilityName,
                desc,
              });
            }
          }
        }
      }
    } catch (error) {
      console.error("Error reading capabilities:", error);
    }

    return capabilityDesc;
  }

  if (name) {
    try {
      const skillFile = await get(`mazmot/capabilities/${name}/SKILL.md`, {
        create: false,
      });

      if (!skillFile) {
        return {
          name: name,
          error: "Capability not found",
        };
      }

      const capabilityMd = await skillFile.text();

      if (!capabilityMd.trim()) {
        return {
          name: name,
          error: "Capability not found",
        };
      }

      return {
        name: name,
        content: capabilityMd,
      };
    } catch (error) {
      return {
        name: name,
        error: "Capability not found",
      };
    }
  }
}

